import jwt
from Cryptodome.Cipher import PKCS1_OAEP
from Cryptodome.PublicKey import RSA
import base64

def decode_and_verify_jwt(token, key):
    try:
        headers_and_claims = jwt.decode(token, key, algorithms=['RS256'])
        public_key = RSA.construct((base64.b64encode(headers_and_claims['header']['kid']), PKCS1_OAEP()))
        if headers_and_claims['alg'] == 'RS256':
            if jwt.decode(token, public_key=public_key, leeway=0, audience='expected_audience', issuer='expected_issuer'):
                return True, headers_and_claims
        return False, {'error': 'Invalid token or incorrect key'}
    except jwt.ExpiredSignatureError:
        return False, {'error': 'Token has expired'}
    except jwt.JWTError as ex:
        return False, {'error': str(ex)}